function buildEndSessionUrl(
  config,
  { configuration, serverMetadata, auth0Logout },
  params,
) {
  // Filter out null and undefined values from params
  const filteredParams = Object.fromEntries(
    Object.entries(params).filter(
      ([, value]) => value !== null && value !== undefined,
    ),
  );

  if (auth0Logout) {
    const { id_token_hint, post_logout_redirect_uri, ...extraParams } =
      filteredParams;
    const logoutUrl = new URL('/v2/logout', serverMetadata.issuer);

    // Add query parameters in the expected order
    if (post_logout_redirect_uri) {
      logoutUrl.searchParams.set('returnTo', post_logout_redirect_uri);
    }
    logoutUrl.searchParams.set('client_id', config.clientID);

    // Add any extra params (already filtered for null/undefined by filteredParams)
    Object.entries(extraParams).forEach(([key, value]) => {
      logoutUrl.searchParams.set(key, value);
    });

    return logoutUrl.toString();
  }

  // Use standard RP-Initiated Logout
  return client.buildEndSessionUrl(configuration, filteredParams).toString();
}

async function getRemoteJWKSet(config) {
  if (jwksClientCache.has(config)) {
    return jwksClientCache.get(config);
  }
  const { serverMetadata } = await getClient(config);
  if (!serverMetadata.jwks_uri) {
    throw new Error('No JWKS URI available for token verification');
  }
  const pkg = require('../package.json');
  const headers = new Headers();
  headers.set(
    'User-Agent',
    config.httpUserAgent || `${pkg.name}/${pkg.version}`,
  );
  if (config.enableTelemetry) {
    headers.set(
      'Auth0-Client',
      Buffer.from(
        JSON.stringify({ name: pkg.name, version: pkg.version }),
      ).toString('base64'),
    );
  }
  const fetchFn = config.customFetch || fetch;
  const JWKS = createRemoteJWKSet(new URL(serverMetadata.jwks_uri), {
    timeoutDuration: config.httpTimeout,
    headers,
    [joseCustomFetch]: (url, options) =>
      fetchFn(url, {
        ...options,
        signal: AbortSignal.timeout(config.httpTimeout),
      }),
  });
  jwksClientCache.set(config, JWKS);
  return JWKS;
}

async function refresh({ tokenEndpointParams } = {}) {
  let { config, req } = weakRef(this);
  const { configuration } = await getClient(config);
  const oldTokenSet = tokenSet.call(this);

  let parameters;
  if (config.tokenEndpointParams || tokenEndpointParams) {
    parameters = { ...config.tokenEndpointParams, ...tokenEndpointParams };
  }

  const newTokenSet = await oidcClient.refreshTokenGrant(
    configuration,
    oldTokenSet.refresh_token,
    parameters,
  );

  // Update the session
  const session = req[config.session.name];
  Object.assign(session, {
    access_token: newTokenSet.access_token,
    // If no new ID token assume the current ID token is valid.
    id_token: newTokenSet.id_token || oldTokenSet.id_token,
    // If no new refresh token assume the current refresh token is valid.
    refresh_token: newTokenSet.refresh_token || oldTokenSet.refresh_token,
    token_type: normalizeTokenType(newTokenSet.token_type),
    expires_at: newTokenSet.expires_in
      ? Math.floor(Date.now() / 1000) + newTokenSet.expires_in
      : undefined,
  });

  // Delete the old token set
  const cachedTokenSet = weakRef(session);
  delete cachedTokenSet.value;

  return this.accessToken;
}

module.exports = async (token, config) => {
  const {
    session: {
      absoluteDuration,
      rolling: rollingEnabled,
      rollingDuration,
      store,
    },
    backchannelLogout,
  } = config;
  const backchannelLogoutStore =
    (backchannelLogout && backchannelLogout.store) || store;
  const maxAge =
    (rollingEnabled
      ? Math.min(absoluteDuration, rollingDuration)
      : absoluteDuration) * 1000;
  const payload = {
    // The "cookie" prop makes the payload compatible with
    // `express-session` stores.
    cookie: {
      expires: Date.now() + maxAge,
      maxAge,
    },
  };
  const set = safePromisify(backchannelLogoutStore.set, backchannelLogoutStore);
  const { iss, sid, sub } = token;
  if (!sid && !sub) {
    throw new Error(`The Logout Token must have a 'sid' or a 'sub'`);
  }
  await Promise.all([
    sid && set(`${iss}|${sid}`, payload),
    sub && set(`${iss}|${sub}`, payload),
  ]);
};

async store(
  key,
  req,
  res,
  { sameSite = 'None', value = this.generateNonce() } = {},
) {
  const isSameSiteNone = sameSite === 'None';
  const { domain, path, secure } = this.sessionCookieConfig;
  const basicAttr = {
    httpOnly: true,
    secure,
    domain,
    path,
  };

  {
    const cookieValue = await generateCookieValue(
      key,
      value,
      this.currentKey,
    );
    // Set the cookie with the SameSite attribute and, if needed, the Secure flag.
    res.cookie(key, cookieValue, {
      ...basicAttr,
      sameSite,
      secure: isSameSiteNone ? true : basicAttr.secure,
    });
  }

  if (isSameSiteNone && this.legacySameSiteCookie) {
    const cookieValue = await generateCookieValue(
      `_${key}`,
      value,
      this.currentKey,
    );
    // Set the fallback cookie with no SameSite or Secure attributes.
    res.cookie(`_${key}`, cookieValue, basicAttr);
  }

  return value;
}

function _resetSessionDocuments(session) {
  for (const doc of session[sessionNewDocuments].keys()) {
    const state = session[sessionNewDocuments].get(doc);
    if (Object.hasOwn(state, 'isNew')) {
      doc.$isNew = state.isNew;
    }
    if (Object.hasOwn(state, 'versionKey')) {
      doc.set(doc.schema.options.versionKey, state.versionKey);
    }

    if (state.modifiedPaths.length > 0 && doc.$__.activePaths.states.modify == null) {
      doc.$__.activePaths.states.modify = {};
    }
    for (const path of state.modifiedPaths) {
      const currentState = doc.$__.activePaths.paths[path];
      if (currentState != null) {
        delete doc.$__.activePaths[currentState][path];
      }
      doc.$__.activePaths.paths[path] = 'modify';
      doc.$__.activePaths.states.modify[path] = true;
    }

    for (const path of state.atomics.keys()) {
      const val = doc.$__getValue(path);
      if (val == null) {
        continue;
      }
      val[arrayAtomicsSymbol] = state.atomics.get(path);
    }
  }
}

_bindEvents() {
  if (this.bindedEvents) {
    return;
  }

  this.bindedEvents = true;

  if (this.driverChangeStream == null) {
    this.$driverChangeStreamPromise.then(
      () => {
        this.driverChangeStream.on('close', () => {
          this.closed = true;
        });

        driverChangeStreamEvents.forEach(ev => {
          this.driverChangeStream.on(ev, data => {
            if (data?.fullDocument != null && this.options?.hydrate) {
              data.fullDocument = this.options.model.hydrate(data.fullDocument);
            }
            this.emit(ev, data);
          });
        });
      },
      () => {} // No need to register events if opening change stream failed
    );

    return;
  }

  this.driverChangeStream.on('close', () => {
    this.closed = true;
  });

  driverChangeStreamEvents.forEach(ev => {
    this.driverChangeStream.on(ev, data => {
      if (data?.fullDocument != null && this.options?.hydrate) {
        data.fullDocument = this.options.model.hydrate(data.fullDocument);
      }
      this.emit(ev, data);
    });
  });
}

function flatten(update, path, options, schema) {
  let keys;
  if (update && isMongooseObject(update) && !Buffer.isBuffer(update)) {
    keys = Object.keys(update.toObject({ transform: false, virtuals: false }) || {});
  } else {
    keys = Object.keys(update || {});
  }

  const numKeys = keys.length;
  const result = {};
  path = path ? path + '.' : '';

  for (let i = 0; i < numKeys; ++i) {
    const key = keys[i];
    const val = update[key];
    result[path + key] = val;

    // Avoid going into mixed paths if schema is specified
    const keySchema = schema?.path?.(path + key);
    const isNested = schema?.nested?.[path + key];
    if (keySchema?.instance === 'Mixed') continue;

    if (shouldFlatten(val)) {
      if (options?.skipArrays && Array.isArray(val)) {
        continue;
      }
      const flat = flatten(val, path + key, options, schema);
      for (const k in flat) {
        result[k] = flat[k];
      }
      if (Array.isArray(val)) {
        result[path + key] = val;
      }
    }

    if (isNested) {
      const paths = Object.keys(schema.paths);
      for (const p of paths) {
        if (p.startsWith(path + key + '.') && !Object.hasOwn(result, p)) {
          result[p] = void 0;
        }
      }
    }
  }

  return result;
}

function applyEmbeddedDiscriminators(schema, seen = new WeakSet(), overwriteExisting = false) {
  if (seen.has(schema)) {
    return;
  }
  seen.add(schema);
  for (const path of Object.keys(schema.paths)) {
    const schemaType = schema.paths[path];
    if (!schemaType.schema) {
      continue;
    }
    applyEmbeddedDiscriminators(schemaType.schema, seen);
    if (!schemaType.schema._applyDiscriminators) {
      continue;
    }
    if (schemaType._appliedDiscriminators && !overwriteExisting) {
      continue;
    }
    for (const discriminatorKey of schemaType.schema._applyDiscriminators.keys()) {
      const {
        schema: discriminatorSchema,
        options
      } = schemaType.schema._applyDiscriminators.get(discriminatorKey);
      applyEmbeddedDiscriminators(discriminatorSchema, seen);
      schemaType.discriminator(
        discriminatorKey,
        discriminatorSchema,
        overwriteExisting ? { ...options, overwriteExisting: true } : options
      );
    }
    schemaType._appliedDiscriminators = true;
  }
}

function applyTimestampsToDoc(schema, obj, options) {
  if (obj == null || typeof obj !== 'object') {
    return;
  }
  if (Array.isArray(obj)) {
    for (const el of obj) {
      applyTimestampsToDoc(schema, el, options);
    }
    return;
  }

  if (schema.discriminators && utils.hasOwnKeys(schema.discriminators)) {
    for (const discriminatorKey of Object.keys(schema.discriminators)) {
      const discriminator = schema.discriminators[discriminatorKey];
      const key = discriminator.discriminatorMapping.key;
      const value = discriminator.discriminatorMapping.value;
      if (obj[key] == value) {
        schema = discriminator;
        break;
      }
    }
  }

  const createdAt = handleTimestampOption(schema.options.timestamps, 'createdAt');
  const updatedAt = handleTimestampOption(schema.options.timestamps, 'updatedAt');
  const currentTime = options?.currentTime;

  let ts = null;
  if (currentTime != null) {
    ts = currentTime();
  } else if (schema.base?.now) {
    ts = schema.base.now();
  } else {
    ts = new Date();
  }

  if (createdAt && obj[createdAt] == null && !options?.isUpdate) {
    obj[createdAt] = ts;
  }
  if (updatedAt) {
    obj[updatedAt] = ts;
  }
}

function getRelatedIndexes({
  baseModelName,
  discriminatorMapping,
  indexes,
  indexesType
}) {
  const discriminatorKey = discriminatorMapping?.key;
  const discriminatorValue = discriminatorMapping?.value;

  if (!discriminatorKey) {
    return indexes;
  }

  const isChildDiscriminatorModel = Boolean(baseModelName);
  if (isChildDiscriminatorModel) {
    return indexes.filter(index => {
      const partialFilterExpression = getPartialFilterExpression(index, indexesType);
      return partialFilterExpression && partialFilterExpression[discriminatorKey] === discriminatorValue;
    });
  }

  return indexes.filter(index => {
    const partialFilterExpression = getPartialFilterExpression(index, indexesType);
    return !partialFilterExpression
      || !partialFilterExpression[discriminatorKey]
      || (hasDollarKeys(partialFilterExpression[discriminatorKey]) && !('$eq' in partialFilterExpression[discriminatorKey]));
  });
}

function analyzeSchema(schema, prefix) {
  prefix || (prefix = '');

  // avoid recursion
  if (stack.indexOf(schema) !== -1) {
    return [];
  }
  stack.push(schema);

  const addedPaths = [];
  schema.eachPath(function(path, type) {
    if (prefix) path = prefix + '.' + path;
    if (type.$isSchemaMap || path.endsWith('.$*')) {
      const plusPath = '+' + path;
      const hasPlusPath = fields && plusPath in fields;
      if (type.options?.select === false && !hasPlusPath) {
        excluded.push(path);
      }
      return;
    }
    let addedPath = analyzePath(path, type);
    // arrays
    if (addedPath == null && !Array.isArray(type) && type.$isMongooseArray && !type.$isMongooseDocumentArray) {
      addedPath = analyzePath(path, type.embeddedSchemaType);
    }
    if (addedPath != null) {
      addedPaths.push(addedPath);
    }

    // nested schemas
    if (type.schema) {
      const _addedPaths = analyzeSchema(type.schema, path);

      // Special case: if discriminator key is the only field that would
      // be projected in, remove it.
      if (exclude === false) {
        checkEmbeddedDiscriminatorKeyProjection(fields, path, type.schema,
          selected, _addedPaths);
      }
    }
  });
  stack.pop();
  return addedPaths;
}

function getMapPath(schema, path) {
  if (schema.mapPaths.length === 0) {
    return null;
  }
  for (const val of schema.mapPaths) {
    const cleanPath = val.path.replace(/\.\$\*/g, '');
    if (path === cleanPath || (path.startsWith(cleanPath + '.') && path.slice(cleanPath.length + 1).indexOf('.') === -1)) {
      return val;
    } else if (val.schema && path.startsWith(cleanPath + '.')) {
      let remnant = path.slice(cleanPath.length + 1);
      remnant = remnant.slice(remnant.indexOf('.') + 1);
      return val.schema.paths[remnant];
    } else if (val.$isSchemaMap && path.startsWith(cleanPath + '.')) {
      let remnant = path.slice(cleanPath.length + 1);
      remnant = remnant.slice(remnant.indexOf('.') + 1);
      const presplitPath = val.$__schemaType._presplitPath;
      if (remnant.indexOf('.') === -1 && presplitPath[presplitPath.length - 1] === '$*') {
        // Handle map of map of primitives
        return val.$__schemaType;
      } else if (remnant.indexOf('.') !== -1 && val.$__schemaType.schema && presplitPath[presplitPath.length - 1] === '$*') {
        // map of map of subdocs (recursive)
        return val.$__schemaType.schema.path(remnant.slice(remnant.indexOf('.') + 1));
      }
    }
  }

  return null;
}

function _createConstructor(schema, options, baseClass) {
  Subdocument || (Subdocument = require('../types/arraySubdocument'));

  // compile an embedded document for this schema
  function EmbeddedDocument() {
    Subdocument.apply(this, arguments);
    if (this.__parentArray == null || this.__parentArray.getArrayParent() == null) {
      return;
    }
    this.$session(this.__parentArray.getArrayParent().$session());
  }

  schema._preCompile();

  const proto = baseClass?.prototype ?? Subdocument.prototype;
  EmbeddedDocument.prototype = Object.create(proto);
  EmbeddedDocument.prototype.$__setSchema(schema);
  EmbeddedDocument.schema = schema;
  EmbeddedDocument.prototype.constructor = EmbeddedDocument;
  EmbeddedDocument.$isArraySubdocument = true;
  EmbeddedDocument.events = new EventEmitter();
  EmbeddedDocument.base = schema.base;

  // apply methods
  for (const i in schema.methods) {
    EmbeddedDocument.prototype[i] = schema.methods[i];
  }

  // apply statics
  for (const i in schema.statics) {
    EmbeddedDocument[i] = schema.statics[i];
  }

  for (const i in EventEmitter.prototype) {
    EmbeddedDocument[i] = EventEmitter.prototype[i];
  }

  EmbeddedDocument.options = options;

  return EmbeddedDocument;
}

function _createConstructor(schema, baseClass, options) {
  // lazy load
  SubdocumentType || (SubdocumentType = require('../types/subdocument'));

  const _embedded = function SingleNested(value, path, parent) {
    this.$__parent = parent;
    SubdocumentType.apply(this, arguments);

    if (parent == null) {
      return;
    }
    this.$session(parent.$session());
  };

  schema._preCompile();

  const proto = baseClass?.prototype ?? SubdocumentType.prototype;
  _embedded.prototype = Object.create(proto);
  _embedded.prototype.$__setSchema(schema);
  _embedded.prototype.constructor = _embedded;
  _embedded.prototype.$__schemaTypeOptions = options;
  _embedded.$__required = options?.required;
  _embedded.base = schema.base;
  _embedded.schema = schema;
  _embedded.$isSingleNested = true;
  _embedded.events = new EventEmitter();
  _embedded.prototype.toBSON = function() {
    return this.toObject(internalToObjectOptions);
  };

  // apply methods
  for (const i in schema.methods) {
    _embedded.prototype[i] = schema.methods[i];
  }

  // apply statics
  for (const i in schema.statics) {
    _embedded[i] = schema.statics[i];
  }

  for (const i in EventEmitter.prototype) {
    _embedded[i] = EventEmitter.prototype[i];
  }

  return _embedded;
}

async function fetchPRNumbers(entries, dryRun = false) {
  const entriesNeedingPRs = entries.filter(
    e => e.prs.length === 0 && e.commitSha,
  );

  if (entriesNeedingPRs.length === 0) {
    return;
  }

  console.log(
    `\n🔍 Fetching PR numbers for ${entriesNeedingPRs.length} new entries...`,
  );

  let fetchedCount = 0;
  const startTime = Date.now();

  for (const entry of entriesNeedingPRs) {
    const prNumber = await findPRNumber(entry.commitSha);
    if (prNumber) {
      entry.prs.push(prNumber);
    }

    fetchedCount++;
    // Progress every 10 lookups
    if (fetchedCount % 10 === 0 || fetchedCount === entriesNeedingPRs.length) {
      const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
      const rate = ((fetchedCount / (Date.now() - startTime)) * 1000).toFixed(
        1,
      );
      process.stdout.write(
        `\r   Fetched ${fetchedCount}/${entriesNeedingPRs.length} PR numbers (${elapsed}s, ~${rate} req/s)`,
      );
    }
  }

  const totalTime = ((Date.now() - startTime) / 1000).toFixed(1);
  const foundCount = entriesNeedingPRs.filter(e => e.prs.length > 0).length;
  console.log(
    `\n   ✓ Found ${foundCount}/${entriesNeedingPRs.length} PR numbers in ${totalTime}s`,
  );
}

export function readAccessRestrictionsFromConfig(
  externalAccessEntryConfig: Config,
): AccessRestrictionsMap | undefined {
  const configs =
    externalAccessEntryConfig.getOptionalConfigArray('accessRestrictions') ??
    [];

  const result: AccessRestrictionsMap = new Map();
  for (const config of configs) {
    const validKeys = ['plugin', 'permission', 'permissionAttribute'];
    for (const key of config.keys()) {
      if (!validKeys.includes(key)) {
        const valid = validKeys.map(k => `'${k}'`).join(', ');
        throw new Error(
          `Invalid key '${key}' in 'accessRestrictions' config, expected one of ${valid}`,
        );
      }
    }

    const pluginId = config.getString('plugin');
    const permissionNames = readPermissionNames(config);
    const permissionAttributes = readPermissionAttributes(config);

    if (result.has(pluginId)) {
      throw new Error(
        `Attempted to declare 'accessRestrictions' twice for plugin '${pluginId}', which is not permitted`,
      );
    }

    result.set(pluginId, {
      ...(permissionNames ? { permissionNames } : {}),
      ...(permissionAttributes ? { permissionAttributes } : {}),
    });
  }

  return result.size ? result : undefined;
}

private async isTargetPluginSupported(
  targetPluginId: string,
): Promise<boolean> {
  if (this.supportedTargetPlugins.has(targetPluginId)) {
    return true;
  }
  const inFlight = this.targetPluginInflightChecks.get(targetPluginId);
  if (inFlight) {
    return inFlight;
  }

  const doCheck = async () => {
    try {
      const res = await fetch(
        `${await this.discovery.getBaseUrl(
          targetPluginId,
        )}/.backstage/auth/v1/jwks.json`,
      );
      if (res.status === 404) {
        return false;
      }

      if (!res.ok) {
        throw new Error(`Failed to fetch jwks.json, ${res.status}`);
      }

      const data = await res.json();
      if (!data.keys) {
        throw new Error(`Invalid jwks.json response, missing keys`);
      }

      this.supportedTargetPlugins.add(targetPluginId);
      return true;
    } catch (error) {
      this.logger.error(
        'Unexpected failure for target JWKS check',
        toError(error),
      );
      return false;
    } finally {
      this.targetPluginInflightChecks.delete(targetPluginId);
    }
  };

  const check = doCheck();
  this.targetPluginInflightChecks.set(targetPluginId, check);
  return check;
}

export async function ensureMysqlDatabaseExists(
  dbConfig: Config,
  ...databases: Array<string>
) {
  const admin = createMysqlDatabaseClient(dbConfig, {
    connection: {
      database: null as unknown as string,
    },
    pool: {
      min: 0,
      acquireTimeoutMillis: 10000,
    },
  });

  try {
    const ensureDatabase = async (database: string) => {
      await admin.raw(`CREATE DATABASE IF NOT EXISTS ??`, [database]);
    };
    await Promise.all(
      databases.map(async database => {
        // For initial setup we use a smaller timeout but several retries. Given that this
        // is a separate connection pool we should never really run into issues with connection
        // acquisition timeouts, but we do anyway. This might be a bug in knex or some other dependency.
        let lastErr: Error | undefined = undefined;
        for (let i = 0; i < 3; i++) {
          try {
            return await ddlLimiter(() => ensureDatabase(database));
          } catch (err) {
            lastErr = err;
          }
          await new Promise(resolve => setTimeout(resolve, 100));
        }
        throw lastErr;
      }),
    );
  } finally {
    await admin.destroy();
  }
}

private async getLastCommitShortHash(url: string): Promise<string> {
  const { name: repoName, owner: project, ref } = parseGitUrl(url);

  let branch = ref;
  if (!branch) {
    branch = await getBitbucketCloudDefaultBranch(
      url,
      this.integration.config,
    );
  }

  const commitsApiUrl = `${this.integration.config.apiBaseUrl}/repositories/${project}/${repoName}/commits/${branch}`;

  const commitsResponse = await fetch(
    commitsApiUrl,
    await getBitbucketCloudRequestOptions(this.integration.config),
  );
  if (!commitsResponse.ok) {
    const message = `Failed to retrieve commits from ${commitsApiUrl}, ${commitsResponse.status} ${commitsResponse.statusText}`;
    if (commitsResponse.status === 404) {
      throw new NotFoundError(message);
    }
    throw new Error(message);
  }

  const commits = await commitsResponse.json();
  if (
    commits &&
    commits.values &&
    commits.values.length > 0 &&
    commits.values[0].hash
  ) {
    return commits.values[0].hash.substring(0, 12);
  }

  throw new Error(`Failed to read response from ${commitsApiUrl}`);
}

